--
-- Table structure for table `caipiao_game`
--

DROP TABLE IF EXISTS `caipiao_game`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `caipiao_game` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `game_id` varchar(50) NOT NULL COMMENT 'ID trò chơi',
  `name` varchar(100) NOT NULL COMMENT 'tên trò chơi',
  `platform` varchar(20) NOT NULL COMMENT 'mã nhà cung cấp',
  `type` varchar(20) NOT NULL COMMENT 'loại trò chơi',
  `icon` varchar(255) DEFAULT '' COMMENT 'Biểu tượng',
  `cover` varchar(255) DEFAULT '' COMMENT 'ảnh bìa',
  `hot` tinyint(1) DEFAULT '0' COMMENT 'phổ biến',
  `new` tinyint(1) DEFAULT '0' COMMENT 'trò chơi',
  `status` varchar(20) DEFAULT 'online' COMMENT 'Trạng thái',
  `sort` int(11) DEFAULT '0' COMMENT 'Sắp xếp',
  `created_at` int(11) NOT NULL,
  `updated_at` int(11) DEFAULT '0',
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_game_id` (`game_id`),
  KEY `idx_platform` (`platform`),
  KEY `idx_type` (`type`)
) ENGINE=InnoDB AUTO_INCREMENT=5819 DEFAULT CHARSET=utf8mb4 COMMENT='游戏列BảngBảng';
/*!40101 SET character_set_client = @saved_cs_client */;

